-- Fase 95: planos explicáveis de orçamento; nenhuma alteração externa.
create table if not exists public.marketing_budget_plans(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id)on delete cascade,name text not null,period_start date not null,period_end date not null,total_budget numeric(14,2)not null check(total_budget>0),currency text not null default'BRL'check(currency='BRL'),evidence jsonb not null,allocations jsonb not null,evidence_hash text not null check(evidence_hash~'^[a-f0-9]{64}$'),status text not null default'draft'check(status in('draft','approved','rejected','expired')),created_by uuid not null references public.profiles(id),decided_by uuid references public.profiles(id),decision_reason text,decided_at timestamptz,created_at timestamptz not null default now(),check(period_end>=period_start and period_end<=period_start+90),unique(organization_id,evidence_hash));
create index if not exists marketing_budget_plans_org_idx on public.marketing_budget_plans(organization_id,created_at desc);alter table public.marketing_budget_plans enable row level security;drop policy if exists marketing_budget_plans_leadership_read on public.marketing_budget_plans;create policy marketing_budget_plans_leadership_read on public.marketing_budget_plans for select to authenticated using(organization_id=(select public.current_organization_id())and exists(select 1 from public.profiles p where p.id=auth.uid()and coalesce(p.commercial_role,case when p.role='admin'then'director'else p.role end)in('director','superintendent')));revoke all on public.marketing_budget_plans from anon,authenticated;grant select on public.marketing_budget_plans to authenticated;
create or replace function public.decide_marketing_budget_plan(p_actor_id uuid,p_organization_id uuid,p_plan_id uuid,p_decision text,p_reason text)returns jsonb language plpgsql security definer set search_path=public,pg_temp as $$declare v_status text;begin if not exists(select 1 from public.profiles where id=p_actor_id and organization_id=p_organization_id and active=true and coalesce(commercial_role,case when role='admin'then'director'else role end)='director')then raise exception 'budget_director_required';end if;if p_decision not in('approved','rejected')or char_length(trim(coalesce(p_reason,'')))<20 then raise exception 'budget_decision_invalid';end if;update public.marketing_budget_plans set status=p_decision,decided_by=p_actor_id,decision_reason=trim(p_reason),decided_at=now()where id=p_plan_id and organization_id=p_organization_id and status='draft'returning status into v_status;if v_status is null then raise exception 'budget_plan_not_decidable';end if;return jsonb_build_object('planId',p_plan_id,'status',v_status,'externalChangeExecuted',false,'automaticBudgetChange',false);end$$;revoke all on function public.decide_marketing_budget_plan(uuid,uuid,uuid,text,text)from public,anon,authenticated;grant execute on function public.decide_marketing_budget_plan(uuid,uuid,uuid,text,text)to service_role;
